  SUBSTR(APA_SECURITY.EQTY_IDY, 1, 100) AS EQTY_IDY,
  SUBSTR(APA_SECURITY.EQTY_IDY_CD, 1, 40) AS EQTY_IDY_CD,
  SUBSTR(APA_SECURITY.EQTY_IDY_GRP, 1, 100) AS EQTY_IDY_GRP,
  SUBSTR(APA_SECURITY.EQTY_IDY_GRP_CD, 1, 40) AS EQTY_IDY_GRP_CD,
  SUBSTR(APA_SECURITY.EQTY_SECT, 1, 100) AS EQTY_SECT,
  SUBSTR(APA_SECURITY.EQTY_SECT_CD, 1, 40) AS EQTY_SECT_CD,
  SUBSTR(APA_SECURITY.EQTY_SUP_SECT, 1, 100) AS EQTY_SUP_SECT,
  SUBSTR(APA_SECURITY.EQTY_SUP_SECT_CD, 1, 40) AS EQTY_SUP_SECT_CD,
  SUBSTR(APA_SECURITY.MODL_STRTG_DTL_AST_CLSS, 1, 100) AS MODL_STRTG_DTL_AST_CLSS,
  SUBSTR(APA_SECURITY.MODL_STRTG_DTL_AST_CLSS_CD, 1, 40) AS MODL_STRTG_DTL_AST_CLSS_CD,
  SUBSTR(APA_SECURITY.MODL_STRTG_SMY_AST_CLSS, 1, 100) AS MODL_STRTG_SMY_AST_CLSS,
  SUBSTR(APA_SECURITY.MODL_STRTG_SMY_AST_CLSS_CD, 1, 40) AS MODL_STRTG_SMY_AST_CLSS_CD,
  APA_SECURITY.PD_CMPOS_DSC AS PD_CMPOS_DSC,
  APA_SECURITY.PD_SHRT_NM AS PD_SHRT_NM,
  APA_SECURITY.PD_DSC AS PD_DSC,
  SUBSTR(APA_SECURITY.RPT_CL_LVL_1, 1, 100) AS RPT_CL_LVL_1,
  SUBSTR(APA_SECURITY.RPT_CL_LVL_2, 1, 100) AS RPT_CL_LVL_2,
  SUBSTR(APA_SECURITY.RPT_STRTG_DTL_AST_CLSS, 1, 100) AS RPT_STRTG_DTL_AST_CLSS,
  SUBSTR(APA_SECURITY.RPT_STRTG_DTL_AST_CLSS_CD, 1, 40) AS RPT_STRTG_DTL_AST_CLSS_CD,
  SUBSTR(APA_SECURITY.RPT_STRTG_SMY_AST_CLSS, 1, 100) AS RPT_STRTG_SMY_AST_CLSS,
  SUBSTR(APA_SECURITY.RPT_STRTG_SMY_AST_CLSS_CD, 1, 40) AS RPT_STRTG_SMY_AST_CLSS_CD,
  APA_SECURITY.FND_FAM AS FND_FAM,
  SUBSTR(APA_SECURITY.SHR_CLSS_TP_CD, 1, 30) AS SHR_CLSS_TP_CD,
  APA_SECURITY.SHR_CLSS_TP AS SHR_CLSS_TP,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_1, 1, 100) AS IMT_CL_LVL_1,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_1_CD, 1, 40) AS IMT_CL_LVL_1_CD,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_2, 1, 100) AS IMT_CL_LVL_2,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_2_CD, 1, 40) AS IMT_CL_LVL_2_CD,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_3, 1, 100) AS IMT_CL_LVL_3,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_3_CD, 1, 40) AS IMT_CL_LVL_3_CD,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_4, 1, 100) AS IMT_CL_LVL_4,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_4_CD, 1, 40) AS IMT_CL_LVL_4_CD,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_5, 1, 100) AS IMT_CL_LVL_5,
  SUBSTR(APA_SECURITY.IMT_CL_LVL_5_CD, 1, 40) AS IMT_CL_LVL_5_CD,
  SUBSTR(FA_NUMBER_V.FA_NUMBER_TYPE_CODE, 1, 3) AS OWN_FA_NUM_TP_CD,
  CODE_SET_VALUE_V.CODE_VALUE_DESCRIPTION AS OWN_FA_NUM_TP,
  CASE WHEN APA_CASH.APA_TP_CD = 'APACSH82' 
THEN 
  APA_CASH.SEC_ORIG_QTY 
ELSE 
null 
END AS BOND_ACRTN_DCN_AMT,
  CASE WHEN APA_CASH.APA_TP_CD = 'APACSH83' 
THEN 
  APA_CASH.SEC_ORIG_QTY 
ELSE 
null 
END AS BOND_AMRZ_PREM_AMT,
  CASE WHEN APA_CASH.APA_TP_CD = 'APACSH84' 
THEN 
  APA_CASH.SEC_ORIG_QTY 
ELSE 
null 
END AS RJ_TRUST_BOOK_VAL_AMT,
  CASE WHEN APA_CASH.APA_TP_CD = 'APACSH85' 
THEN 
  APA_CASH.SEC_ORIG_QTY 
ELSE 
null 
END AS RJ_TRUST_RLZD_TAX_GAIN_OR_LOSS_AMT,
  CASE WHEN APA_SECURITY.APA_TP_CD = 'APASEC81' 
THEN 
  APA_SECURITY.SEC_ORIG_QTY 
ELSE 
null 
END AS BFR_REPYMT_FACE_VAL_AMT,
  CASE WHEN APA_SECURITY.APA_TP_CD = 'APASEC83' 
THEN 
  APA_SECURITY.SEC_ORIG_QTY 
ELSE 
null 
END AS BFR_INCM_PYMT_FACE_VAL_AMT,
  CASE WHEN APA_SECURITY.APA_TP_CD = 'APASEC91' 
THEN 
  APA_SECURITY.SEC_ORIG_QTY 
ELSE 
null 
END AS BASE_POS_QTY,
  CASE WHEN APA_SECURITY.APA_TP_CD = 'APASEC93' 
THEN 
  APA_SECURITY.SEC_ORIG_QTY 
ELSE 
null 
END AS NO_SIS_SCR_MVMT_TXN_QTY,
  CASE WHEN APA_SECURITY.APA_TP_CD = 'APASEC93' 
THEN 
  APA_SECURITY.SEC_PRC_IN_TXN_CCY 
ELSE 
null 
END AS NO_SIS_SCR_MVMT_TXN_PRC,
  CASE WHEN APA_SECURITY.APA_TP_CD = 'APASEC94' 
THEN 
  APA_SECURITY.SEC_ORIG_QTY 
ELSE 
null 
END AS REIVS_SHR_QTY,
  CASE WHEN APA_SECURITY.APA_TP_CD = 'APASEC94' 
THEN 
  APA_SECURITY.SEC_PRC_IN_TXN_CCY 
ELSE 
null 
END AS REIVS_PRC
FROM (SELECT /*+ NO_MERGE */ * FROM CCAL_REPL_OWNER.TXN WHERE ACTV_F = 'Y' AND ROWNUM <= 100) TXN
LEFT JOIN (  SELECT a.*,    a.ORIG_QTY AS SEC_ORIG_QTY,    a.SCR_PRC_IN_TXN_CCY AS SEC_PRC_IN_TXN_CCY,    a.SCR_PRC_IN_SBC AS SEC_SRC_PRC_IN_SBC,    a.OPT_SYMB AS SCR_OPT_SYMB,    a.PD_ID AS SEC_PD_ID,    a.ISIN AS SEC_SRC_CUSIP,    a.STM_BASE_CCY_AMT AS SBC_AMT,    a.STM_BASE_CCY_EXG_RATE AS SBC_EXG_RATE,    a.STM_BASE_CCY_CLC_DTM AS SBC_CCY_CALC_DT,    c.CL_VAL_CODE AS APA_TP_CD,    c.CL_VAL_NM AS APA_TP_NM,    c.DSC AS APA_TP_DSC,    db_cr.CL_VAL_CODE AS DB_CR_CD,    db_cr.CL_VAL_NM AS DB_CR_NM,    acg.CL_VAL_CODE AS ACG_TP_CD,    acg.CL_VAL_NM AS ACG_TP_NM,    CAST(NULL AS VARCHAR2(50)) AS AVY_CGY,    CAST(NULL AS VARCHAR2(50)) AS AVY_TP,    CAST(NULL AS NUMBER) AS AVY_CL_ID,    CAST(NULL AS NUMBER) AS CCY_DIM_ID,    CAST(NULL AS NUMBER) AS CIRD_PD_ID,    CAST(NULL AS VARCHAR2(50)) AS DB_CARD_ORIG_CCY,    CAST(NULL AS VARCHAR2(50)) AS DB_CARD_ORIG_CCY_CD,    CAST(NULL AS VARCHAR2(4000)) AS DSC_TRAILER_1,    CAST(NULL AS VARCHAR2(4000)) AS ALT_DSC_TRAILER_2,    CAST(NULL AS VARCHAR2(50)) AS DSPL_AVY_CGY,    CAST(NULL AS VARCHAR2(50)) AS DSPL_AVY_TP,    CAST(NULL AS VARCHAR2(100)) AS EQTY_IDY,    CAST(NULL AS VARCHAR2(100)) AS EQTY_IDY_CD,    CAST(NULL AS VARCHAR2(100)) AS EQTY_IDY_GRP,    CAST(NULL AS VARCHAR2(100)) AS EQTY_IDY_GRP_CD,    CAST(NULL AS VARCHAR2(100)) AS EQTY_SECT,    CAST(NULL AS VARCHAR2(100)) AS EQTY_SECT_CD,    CAST(NULL AS VARCHAR2(100)) AS EQTY_SUP_SECT,    CAST(NULL AS VARCHAR2(100)) AS EQTY_SUP_SECT_CD,    CAST(NULL AS VARCHAR2(100)) AS FND_FAM,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_1,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_1_CD,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_2,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_2_CD,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_3,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_3_CD,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_4,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_4_CD,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_5,    CAST(NULL AS VARCHAR2(100)) AS IMT_CL_LVL_5_CD,    CAST(NULL AS VARCHAR2(100)) AS MODL_STRTG_DTL_AST_CLSS,    CAST(NULL AS VARCHAR2(100)) AS MODL_STRTG_DTL_AST_CLSS_CD,    CAST(NULL AS VARCHAR2(100)) AS MODL_STRTG_SMY_AST_CLSS,    CAST(NULL AS VARCHAR2(100)) AS MODL_STRTG_SMY_AST_CLSS_CD,    CAST(NULL AS NUMBER) AS NNA_CGY_ID,    CAST(NULL AS VARCHAR2(100)) AS NNA_CGY_NM,    CAST(NULL AS NUMBER) AS OFST_ORIG_SRC_STM_AR_ID,    CAST(NULL AS VARCHAR2(100)) AS OFST_AR_ORIG_SRC_STM_CD,    CAST(NULL AS VARCHAR2(100)) AS OFST_AR_SETL_TP_CD,    CAST(NULL AS VARCHAR2(4000)) AS OFST_AR_SETL_TP_DSC,    CAST(NULL AS VARCHAR2(4000)) AS PD_DSC,    CAST(NULL AS VARCHAR2(100)) AS PD_SHRT_NM,    CAST(NULL AS VARCHAR2(100)) AS RPT_CL_LVL_1,    CAST(NULL AS VARCHAR2(100)) AS RPT_CL_LVL_2,    CAST(NULL AS VARCHAR2(100)) AS RPT_STRTG_DTL_AST_CLSS,    CAST(NULL AS VARCHAR2(100)) AS RPT_STRTG_DTL_AST_CLSS_CD,    CAST(NULL AS VARCHAR2(100)) AS RPT_STRTG_SMY_AST_CLSS,    CAST(NULL AS VARCHAR2(100)) AS RPT_STRTG_SMY_AST_CLSS_CD,    CAST(NULL AS VARCHAR2(100)) AS SHR_CLSS_TP,    CAST(NULL AS VARCHAR2(100)) AS SHR_CLSS_TP_CD,    CAST(NULL AS NUMBER) AS AGRT_ORIG_FEES,    CAST(NULL AS NUMBER) AS AGRT_STMT_FEES  FROM CCAL_REPL_OWNER.APA a  JOIN CCAL_REPL_OWNER.CL_VAL c ON c.CL_VAL_ID = a.APA_TP_ID  LEFT JOIN CCAL_REPL_OWNER.CL_VAL db_cr ON db_cr.CL_VAL_ID = a.DB_CR_ID  LEFT JOIN CCAL_REPL_OWNER.CL_VAL acg ON acg.CL_VAL_ID = a.ACG_TP_ID  WHERE REGEXP_LIKE(c.CL_VAL_CODE, '^APASEC[0-7][0-9]')) APA_SECURITY ON APA_SECURITY.EXEC_ID = TXN.TXN_ID
LEFT JOIN (  SELECT a.*,    a.ORIG_QTY AS SEC_ORIG_QTY,    a.PD_ID AS CASH_PD_ID,    a.STM_BASE_CCY_AMT AS SBC_AMT,    a.STM_BASE_CCY_EXG_RATE AS SBC_EXG_RATE,    a.STM_BASE_CCY_CLC_DTM AS SBC_CCY_CALC_DT,    a.TXN_AMT AS ACT_CMSN_AMT,    a.TXN_AMT AS TRD_PCS_FEE_AMT,    a.TXN_AMT AS SEC_FEE_AMT,    a.TXN_AMT AS ACR_INT_AMT,    a.TXN_AMT AS CNCSN_AMT,    a.TXN_AMT AS CDSC_AMT,    a.TXN_AMT AS OTHR_FEE_AMT,    c.CL_VAL_CODE AS APA_TP_CD,    c.CL_VAL_NM AS APA_TP_NM,    c.DSC AS APA_TP_DSC,    db_cr.CL_VAL_CODE AS DB_CR_CD,    db_cr.CL_VAL_NM AS DB_CR_NM,    acg.CL_VAL_CODE AS ACG_TP_CD,    acg.CL_VAL_NM AS ACG_TP_NM,    cash_tp.CL_VAL_CODE AS CASH_POS_TP_CD,    cash_tp.CL_VAL_NM AS CASH_POS_TP_NM,    sale.CL_VAL_CODE AS SALE_CHRG_RATE_TP_CD,    sale.CL_VAL_NM AS SALE_CHRG_RATE_TP_NM,    CAST(NULL AS VARCHAR2(50)) AS AVY_CGY,    CAST(NULL AS VARCHAR2(50)) AS AVY_TP,    CAST(NULL AS NUMBER) AS AVY_CL_ID,    CAST(NULL AS NUMBER) AS CCY_DIM_ID,    CAST(NULL AS NUMBER) AS CIRD_PD_ID,    CAST(NULL AS VARCHAR2(4000)) AS DSC_TRAILER_1,    CAST(NULL AS VARCHAR2(4000)) AS ALT_DSC_TRAILER_2,    CAST(NULL AS VARCHAR2(50)) AS DSPL_AVY_CGY,    CAST(NULL AS VARCHAR2(50)) AS DSPL_AVY_TP,    CAST(NULL AS NUMBER) AS NNA_CGY_ID,    CAST(NULL AS VARCHAR2(100)) AS NNA_CGY_NM,    CAST(NULL AS NUMBER) AS OFST_ORIG_SRC_STM_AR_ID,    CAST(NULL AS VARCHAR2(100)) AS OFST_AR_ORIG_SRC_STM_CD,    CAST(NULL AS VARCHAR2(100)) AS OFST_AR_SETL_TP_CD,    CAST(NULL AS VARCHAR2(4000)) AS OFST_AR_SETL_TP_DSC,    CAST(NULL AS NUMBER) AS AGRT_ORIG_FEES,    CAST(NULL AS NUMBER) AS AGRT_STMT_FEES  FROM CCAL_REPL_OWNER.APA a  JOIN CCAL_REPL_OWNER.CL_VAL c ON c.CL_VAL_ID = a.APA_TP_ID  LEFT JOIN CCAL_REPL_OWNER.CL_VAL db_cr ON db_cr.CL_VAL_ID = a.DB_CR_ID  LEFT JOIN CCAL_REPL_OWNER.CL_VAL acg ON acg.CL_VAL_ID = a.ACG_TP_ID  LEFT JOIN CCAL_REPL_OWNER.CL_VAL cash_tp ON cash_tp.CL_VAL_ID = a.CASH_POS_TP_ID  LEFT JOIN CCAL_REPL_OWNER.CL_VAL sale ON sale.CL_VAL_ID = a.SALE_CHRG_RATE_TP_ID  WHERE REGEXP_LIKE(c.CL_VAL_CODE, '^APACSH[0-7][0-9]')) APA_CASH ON APA_CASH.EXEC_ID = TXN.TXN_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL TRANSACTION_TYPE ON TRANSACTION_TYPE.CL_VAL_ID = TXN.TXN_TP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL TRANSACTION_SUBTYPE ON TRANSACTION_SUBTYPE.CL_VAL_ID = TXN.TXN_SBTP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL EXECUTION_TYPE ON EXECUTION_TYPE.CL_VAL_ID = TXN.EXEC_TP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL EXECUTION_SUBTYPE ON EXECUTION_SUBTYPE.CL_VAL_ID = TXN.EXEC_SBTP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL CD_CL_VAL ON CD_CL_VAL.CL_VAL_ID = TXN.DOL_IND_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL OMS_EXEC_TP ON OMS_EXEC_TP.CL_VAL_ID = TXN.OMS_EXEC_TP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL SIS_DLTD_EV ON SIS_DLTD_EV.CL_VAL_ID = TXN.SRC_BUY_SELL_MULTI_ID AND SIS_DLTD_EV.CL_SCM_ID = 99
LEFT JOIN CCAL_REPL_OWNER.CL_VAL SRC_CNCL_RSN ON SRC_CNCL_RSN.CL_VAL_ID = TXN.SRC_CNCL_RSN_ID AND SRC_CNCL_RSN.CL_SCM_ID = 102
LEFT JOIN CCAL_REPL_OWNER.CL_VAL TXN_RCNCL_ST ON TXN_RCNCL_ST.CL_VAL_ID = TXN.TXN_ST_ID AND TXN_RCNCL_ST.CL_SCM_ID = 12
LEFT JOIN CCAL_REPL_OWNER.CL_VAL IMPACT_TRD_LGCY_TRD_CPCTY_TP_DIM ON IMPACT_TRD_LGCY_TRD_CPCTY_TP_DIM.CL_VAL_ID = TXN.LGCY_TRD_CPCTY_TP_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL DRVD_TRD_CPCTY ON DRVD_TRD_CPCTY.CL_VAL_ID = TXN.DRVD_TRD_CPCTY_TP_ID AND DRVD_TRD_CPCTY.CL_SCM_ID = 104
LEFT JOIN COMMON_OWNER.DATE_DIM TD_DATE_DIM ON TD_DATE_DIM.CAL_DT = TXN.TD
LEFT JOIN COMMON_OWNER.DATE_DIM SD_DATE_DIM ON SD_DATE_DIM.CAL_DT = TXN.SD
LEFT JOIN COMMON_OWNER.SRC_STM_DIM SRC_STM_DIM ON SRC_STM_DIM.SRC_STM_ID = TXN.SRC_STM_ID
LEFT JOIN TRANSACTIONS_OWNER.TRD_SLCT_TP_DIM TRD_SLCT_TP_DIM ON TRD_SLCT_TP_DIM.TRD_SLCT_TP_ID = TXN.TRD_SLCT_TP_ID
LEFT JOIN TRANSACTIONS_OWNER.SRC_ENTR_CNL_TP_DIM SRC_ENTR_CNL_TP_DIM ON SRC_ENTR_CNL_TP_DIM.SRC_ENTR_CNL_TP_ID = TXN.SRC_ENTR_CNL_TP_ID
LEFT JOIN TRANSACTIONS_OWNER.SRC_PCS_TP_DIM SRC_PCS_TP_DIM ON SRC_PCS_TP_DIM.SRC_PCS_TP_ID = TXN.SRC_PCS_TP_ID
LEFT JOIN TRANSACTIONS_OWNER.LGCY_TRD_CPCTY_TP_DIM LGCY_TRD_CPCTY_TP_DIM ON LGCY_TRD_CPCTY_TP_DIM.LGCY_TRD_CPCTY_TP_ID = TXN.LGCY_TRD_CPCTY_TP_ID
LEFT JOIN TRANSACTIONS_OWNER.LGCY_MKT_TP_DIM LGCY_MKT_TP_DIM ON LGCY_MKT_TP_DIM.LGCY_MKT_TP_ID = TXN.LGCY_MKT_TP_ID
LEFT JOIN TRANSACTIONS_OWNER.LGCY_CNCL_CMPLN_SRC_TP_DIM LGCY_CNCL_CMPLN_SRC_TP_DIM ON LGCY_CNCL_CMPLN_SRC_TP_DIM.LGCY_CNCL_CMPLN_SRC_TP_ID = TXN.LGCY_CNCL_CMPLN_SRC_TP_ID
LEFT JOIN TRANSACTIONS_OWNER.LGCY_CNCL_CMPLN_RSN_TP_DIM LGCY_CNCL_CMPLN_RSN_TP_DIM ON LGCY_CNCL_CMPLN_RSN_TP_DIM.LGCY_CNCL_CMPLN_RSN_TP_ID = TXN.LGCY_CNCL_CMPLN_RSN_TP_ID
LEFT JOIN CIRD_OWNER.EXG_DIM EXG_DIM ON EXG_DIM.EXG_CD = TXN.EXG_CODE AND TXN.TD >= EXG_DIM.EFF_DT AND TXN.TD < EXG_DIM.END_DT
LEFT JOIN (  SELECT SRC_TXN_ID, TRGT_TXN_ID, TXN_RLTNP_TP_ID,         ROW_NUMBER() OVER (PARTITION BY SRC_TXN_ID ORDER BY TXN_RLTNP_TP_ID) AS RN  FROM CCAL_REPL_OWNER.TXN_RLTNP WHERE ACTV_F = 'Y') TXN_RLTNP ON TXN_RLTNP.SRC_TXN_ID = TXN.TXN_ID AND TXN_RLTNP.RN = 1
LEFT JOIN CCAL_REPL_OWNER.TXN TXN_RLTNP_TXN ON TXN_RLTNP_TXN.TXN_ID = TXN_RLTNP.TRGT_TXN_ID
LEFT JOIN COMMON_OWNER.SRC_STM_DIM TXN_RLTNP_SRC_STM_DIM ON TXN_RLTNP_SRC_STM_DIM.SRC_STM_ID = TXN_RLTNP_TXN.SRC_STM_ID
LEFT JOIN CCAL_REPL_OWNER.CL_VAL REL_TXN_RLTNP_TP ON REL_TXN_RLTNP_TP.CL_VAL_ID = TXN_RLTNP.TXN_RLTNP_TP_ID AND REL_TXN_RLTNP_TP.CL_SCM_ID = 4
LEFT JOIN CCAL_REPL_OWNER.ACATS_BROKER ACATS_BROKER ON ACATS_BROKER.BROKER_ID = TXN.ORIG_SRC_STM_CODE
LEFT JOIN CCAL_REPL_OWNER.SHDW_TXN_TP SHDW_TXN_TP ON SHDW_TXN_TP.SRC_TXN_TP = TXN.SRC_TXN_TP
LEFT JOIN REFERENCE_REPL_OWNER.IMPCT_ACTION_LKU IMPCT_ACTION_LKU ON IMPCT_ACTION_LKU.ACTION_CODE = TXN.SRC_ACTN_CODE
LEFT JOIN CCSI_OWNER.AR_GRP_SUBDIM AR_GRP_SUBDIM ON AR_GRP_SUBDIM.AR_ID = TXN.AR_ID AND TXN.TD >= AR_GRP_SUBDIM.EFF_DT AND TXN.TD < AR_GRP_SUBDIM.END_DT
LEFT JOIN CCSI_OWNER.AR_DIM AR_DIM ON AR_DIM.AR_ID = TXN.AR_ID AND TXN.TD >= AR_DIM.EFF_DT AND TXN.TD < AR_DIM.END_DT
LEFT JOIN CCSI_OWNER.AR_AC_SUBDIM AR_AC_SUBDIM ON AR_AC_SUBDIM.AR_ID = TXN.AR_ID AND AR_AC_SUBDIM.DEP_AC_SETUP_ID = APA_CASH.AC_ID AND TXN.TD >= AR_AC_SUBDIM.EFF_DT AND TXN.TD < AR_AC_SUBDIM.END_DT
LEFT JOIN CCAL_REPL_OWNER.TXN_SRC_TAX_CODE_LKUP TXN_SRC_TAX_CODE_LKUP ON TXN_SRC_TAX_CODE_LKUP.SRC_TAX_CODE_ID = TXN.SRC_TAX_CODE_ID AND TXN_SRC_TAX_CODE_LKUP.ACTV_F = 'Y'
LEFT JOIN SSDS_DAL_OWNER.FA_NUMBER_V FA_NUMBER_V ON FA_NUMBER_V.FA_NUMBER = AR_GRP_SUBDIM.FA_NUM AND TXN.TD >= FA_NUMBER_V.EFFECTIVE_DATE AND TXN.TD < FA_NUMBER_V.END_DATE
LEFT JOIN SSDS_DAL_OWNER.CODE_SET_VALUE_V CODE_SET_VALUE_V ON CODE_SET_VALUE_V.CODE_VALUE_ID = FA_NUMBER_V.FA_NUMBER_TYPE_CODE_ID AND TXN.TD >= CODE_SET_VALUE_V.EFFECTIVE_DATE AND TXN.TD < CODE_SET_VALUE_V.END_DATE
LEFT JOIN CCSI_OWNER.AR_DIM BKR_AR_DIM ON AR_GRP_SUBDIM.LINKED_BKR_AR_ID = BKR_AR_DIM.AR_ID AND TXN.TD >= BKR_AR_DIM.EFF_DT AND TXN.TD < BKR_AR_DIM.END_DT
LEFT JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V OWN_FA_ENT ON FA_NUMBER_V.FA_NUMBER_ENTITY_CODE = OWN_FA_ENT.ENTITY_CODE_LONG AND TXN.TD >= OWN_FA_ENT.EFFECTIVE_DATE AND TXN.TD < OWN_FA_ENT.END_DATE AND OWN_FA_ENT.ENTITY_RECYCLED_BOOLEAN = 0 AND OWN_FA_ENT.ENTITY_FINANCIAL_RIA_BOOLEAN = 0
LEFT JOIN SSDS_DAL_OWNER.FA_NUMBER_V FA_NUMBER_V2 ON FA_NUMBER_V.RESPONSIBLE_PARTY_EMPLOYEE_ID = FA_NUMBER_V2.RESPONSIBLE_PARTY_EMPLOYEE_ID AND TXN.TD >= FA_NUMBER_V2.EFFECTIVE_DATE AND TXN.TD < FA_NUMBER_V2.END_DATE AND FA_NUMBER_V2.FA_NUMBER_TYPE_CODE IN ('pri','PRI')
